from pathlib import Path

source_type = config.get("source_type", "workspace")
upload_target = "local" if str(config.get("upload_target", "gcs")).lower() == "local" else "gcs"
source_dir = resolve_input_path(config["source_dir"], source_type)
nonbdo_matrix = resolve_input_path(config["nonbdo_matrix"], source_type)
bdo_matrix = resolve_input_path(config["bdo_matrix"], source_type)
credentials_file = None
if upload_target != "local" or config.get("credentials_file"):
    credentials_file = resolve_input_path(config["credentials_file"], source_type)

required_paths = {
    "source_dir": source_dir,
    "nonbdo_matrix": nonbdo_matrix,
    "bdo_matrix": bdo_matrix,
}
if upload_target != "local":
    required_paths["credentials_file"] = credentials_file

for name, path in required_paths.items():
    if not Path(path).exists():
        raise FileNotFoundError(f"{name} does not exist: {path}")

run_dir = Path(workspace_dir) / config.get("run_dir", ".workflow_runs/raw_router")
run_dir.mkdir(parents=True, exist_ok=True)

paths = {
    "source_dir": str(source_dir),
    "nonbdo_matrix": str(nonbdo_matrix),
    "bdo_matrix": str(bdo_matrix),
    "run_dir": str(run_dir),
}
if credentials_file:
    paths["credentials_file"] = str(credentials_file)

result = {
    "status": "validated",
    "delivery_target": upload_target,
    "paths": paths,
}

import json
from pathlib import Path

globals().update({
    "json": json,
    "Path": Path,
})


def group_examples_by_extension(items):
    groups = {}
    for item in items:
        extension = str(item.get("extension") or Path(item.get("file_name", "")).suffix or "no extension").lower()
        if extension not in groups:
            groups[extension] = {
                "extension": extension,
                "count": 0,
                "example": item.get("file_name"),
                "reason": item.get("reason", "scanned"),
            }
        groups[extension]["count"] += 1
    return list(groups.values())

validated = context.get("Validate Environment", {}).get("result", {})
paths = validated.get("paths", {})

if not paths:
    raise ValueError("Missing Validate Environment result paths")

source_dir = Path(paths["source_dir"])
run_dir = Path(paths["run_dir"])
run_dir.mkdir(parents=True, exist_ok=True)

valid_extensions = [
    str(ext).lower()
    for ext in config.get("valid_extensions", [".csv", ".xlsx", ".xls", ".txt", ".zip", ".pdf"])
]

skip_name_contains = [
    str(marker).lower()
    for marker in config.get("skip_name_contains", ["cm.bdo"])
]

if not source_dir.exists():
    raise FileNotFoundError(f"Source directory does not exist: {source_dir}")

all_files = []
for path in source_dir.rglob("*"):
    stop_if_requested()
    if path.is_file():
        all_files.append(path)

candidate_files = []
skipped_files = []

for file_path in all_files:
    stop_if_requested()

    extension = file_path.suffix.lower()
    file_name_lower = file_path.name.lower()

    base_item = {
        "file_path": str(file_path),
        "file_name": file_path.name,
        "extension": extension,
        "source_dir": str(source_dir),
    }

    try:
        base_item["relative_path"] = str(file_path.relative_to(source_dir))
    except ValueError:
        base_item["relative_path"] = file_path.name

    if extension not in valid_extensions:
        skipped_files.append({
            **base_item,
            "reason": "unsupported_extension",
        })
        continue

    skip_marker = None
    for marker in skip_name_contains:
        if marker and marker in file_name_lower:
            skip_marker = marker
            break

    if skip_marker:
        skipped_files.append({
            **base_item,
            "reason": f"contains_{skip_marker}",
        })
        continue

    candidate_files.append(base_item)

candidates_file = run_dir / "candidate_files.json"
skipped_file = run_dir / "skipped_files.json"

candidates_file.write_text(json.dumps(candidate_files, ensure_ascii=False), encoding="utf-8")
skipped_file.write_text(json.dumps(skipped_files, ensure_ascii=False), encoding="utf-8")

log(
    f"Scanned files: total={len(all_files)}, candidates={len(candidate_files)}, skipped={len(skipped_files)}",
    level="info",
)

result = {
    "status": "scanned",
    "source_dir": str(source_dir),
    "candidates_file": str(candidates_file),
    "skipped_file": str(skipped_file),
    "total_scanned": len(all_files),
    "total_candidates": len(candidate_files),
    "total_skipped": len(skipped_files),
    "valid_extensions": valid_extensions,
    "sample_candidates": group_examples_by_extension(candidate_files),
    "sample_skipped": group_examples_by_extension(skipped_files),
    "candidate_extension_summary": group_examples_by_extension(candidate_files),
    "skipped_extension_summary": group_examples_by_extension(skipped_files),
}

import io
import re
import json
import zipfile
from pathlib import Path

import polars as pl
from pypdf import PdfReader
from pyxlsb import open_workbook

globals().update({
    "io": io,
    "re": re,
    "json": json,
    "zipfile": zipfile,
    "Path": Path,
    "pl": pl,
    "PdfReader": PdfReader,
    "open_workbook": open_workbook,
})

scan = context.get("Scan Candidate Files", {}).get("result")
if not scan:
    raise ValueError("Missing Scan Candidate Files result")

candidates_file = Path(scan["candidates_file"])
candidate_files = json.loads(candidates_file.read_text(encoding="utf-8"))
scan_valid_extensions = {
    str(ext).lower()
    for ext in scan.get("valid_extensions", [])
    if ext
}

validated = context.get("Validate Environment", {}).get("result", {})
run_dir = Path(validated["paths"]["run_dir"])

default_date = config.get("default_date", {})
DEFAULT_YEAR = str(default_date.get("year", "2026"))
DEFAULT_MONTH = str(default_date.get("month", "05")).zfill(2)
DEFAULT_DAY = str(default_date.get("day", "15")).zfill(2)

max_rows = int(config.get("scan_content_rows", 30))
max_branch_rows = int(config.get("scan_branch_rows", 50))
pdf_max_pages = int(config.get("pdf_max_pages", 5))

SUPPORTED_SPREADSHEET_EXTENSIONS = set(config.get(
    "spreadsheet_extensions",
    [".xlsx", ".xls", ".xlsb", ".xlsm"],
))
SUPPORTED_TEXT_EXTENSIONS = set(config.get(
    "text_extensions",
    [".csv", ".txt", ".dat", ".tsv", ".log"],
))
AUTO_TEXT_EXTENSIONS = {
    ext
    for ext in scan_valid_extensions
    if ext not in SUPPORTED_SPREADSHEET_EXTENSIONS and ext not in {".zip", ".pdf"}
}
SUPPORTED_TEXT_EXTENSIONS.update(AUTO_TEXT_EXTENSIONS)

VALID_YEARS = {"2025", "2026", "2027", "2028"}
MONTH_NAME_MAP = {
    "jan": "01",
    "feb": "02",
    "mar": "03",
    "apr": "04",
    "may": "05",
    "jun": "06",
    "jul": "07",
    "aug": "08",
    "sep": "09",
    "sept": "09",
    "oct": "10",
    "nov": "11",
    "dec": "12",
}

def valid_date_parts(year, month, day, valid_years=VALID_YEARS):
    year = str(year).zfill(4)
    month = str(month).zfill(2)
    day = str(day).zfill(2)
    if year not in valid_years:
        return None
    try:
        month_int = int(month)
        day_int = int(day)
    except ValueError:
        return None
    if not 1 <= month_int <= 12:
        return None
    if not 1 <= day_int <= 31:
        return None
    return year, month, day



def read_xlsb_with_pyxlsb(file_path, open_workbook_fn=open_workbook, pl_arg=pl):
    rows = []
    max_width = 0
    with open_workbook_fn(str(file_path)) as workbook:
        sheet_name = workbook.sheets[0]
        with workbook.get_sheet(sheet_name) as sheet:
            for row in sheet.rows():
                values = [cell.v for cell in row]
                rows.append(values)
                max_width = max(max_width, len(values))
    normalized_rows = [row + [None] * (max_width - len(row)) for row in rows]
    columns = [f"column_{index + 1}" for index in range(max_width)]
    return pl_arg.DataFrame(normalized_rows, schema=columns, orient="row")


def group_examples_by_extension(items):
    groups = {}
    for item in items:
        extension = str(item.get("extension") or Path(item.get("file_name", "")).suffix or "no extension").lower()
        if extension not in groups:
            groups[extension] = {
                "extension": extension,
                "count": 0,
                "example": item.get("file_name"),
                "reason": item.get("reason", "signals_extracted"),
            }
        groups[extension]["count"] += 1
    return list(groups.values())


def parse_pos_filename(filename, Path=Path, re=re):
    fn = Path(filename).name

    tl_match = re.match(
        r"^tl(\d{3})(\d{4})(\d{2})(\d{2})(\d{4})",
        fn,
        flags=re.IGNORECASE,
    )
    if tl_match:
        company, branch, month, day, year = tl_match.groups()
        return {
            "family": "tl",
            "company": company.zfill(3),
            "branch": branch.zfill(4),
            "year": year.zfill(4),
            "month": month.zfill(2),
            "day": day.zfill(2),
        }

    j_match = re.match(
        r"^j(\d{3})(\d{4})(\d{2})(\d{2})(\d{2})",
        fn,
        flags=re.IGNORECASE,
    )
    if j_match:
        company, branch, month, day, year2 = j_match.groups()
        return {
            "family": "j",
            "company": company.zfill(3),
            "branch": branch.zfill(4),
            "year": f"20{year2.zfill(2)}",
            "month": month.zfill(2),
            "day": day.zfill(2),
        }

    return None


def extract_date_from_filename(
    filename,
    re=re,
    Path=Path,
    default_year=DEFAULT_YEAR,
    default_month=DEFAULT_MONTH,
    default_day=DEFAULT_DAY,
    valid_date_parts_fn=valid_date_parts,
    month_name_map=MONTH_NAME_MAP,
):
    fallback = valid_date_parts_fn(default_year, default_month, default_day) or (str(default_year), str(default_month).zfill(2), str(default_day).zfill(2))
    file_text = Path(filename).name

    month_name_match = re.search(
        r"(?<!\d)(20\d{2})(jan|feb|mar|apr|may|jun|jul|aug|sep|sept|oct|nov|dec)[a-z]*(\d{1,2})(?!\d)",
        file_text,
        flags=re.IGNORECASE,
    )
    if month_name_match:
        parsed = valid_date_parts_fn(
            month_name_match.group(1),
            month_name_map[month_name_match.group(2).lower()[:3]],
            month_name_match.group(3),
        )
        if parsed:
            return parsed

    pure_digits_match = re.search(r"(?<!\d)(20\d{2})(\d{2})(\d{2})(?!\d)", file_text)
    if pure_digits_match:
        parsed = valid_date_parts_fn(*pure_digits_match.groups())
        if parsed:
            return parsed

    separated_match = re.search(
        r"(?<!\d)(20\d{2})[-_](\d{1,2})[-_](\d{1,2})(?!\d)|(?<!\d)(\d{1,2})(\d{1,2})(20\d{2})(?!\d)",
        file_text,
    )
    if separated_match:
        groups = separated_match.groups()
        if groups[0]:
            parsed = valid_date_parts_fn(groups[0], groups[1], groups[2])
        else:
            parsed = valid_date_parts_fn(groups[5], groups[3], groups[4])
        if parsed:
            return parsed

    return fallback


def extract_date_from_text(text, filename, re=re, extract_date_from_filename=extract_date_from_filename, valid_date_parts_fn=valid_date_parts):
    if not text:
        return extract_date_from_filename(filename)

    match = re.search(
        r"(\d{4})[-/](\d{1,2})[-/](\d{1,2})|(\d{1,2})[-/](\d{1,2})[-/](\d{4})",
        text,
    )
    if match:
        groups = match.groups()
        if groups[0]:
            parsed = valid_date_parts_fn(groups[0], groups[1], groups[2])
        else:
            parsed = valid_date_parts_fn(groups[5], groups[3], groups[4])
        if parsed:
            return parsed

    return extract_date_from_filename(filename)


def extract_date_metadata(df, filename, re=re, extract_date_from_filename=extract_date_from_filename, valid_date_parts_fn=valid_date_parts):
    if df is None or df.height == 0:
        return extract_date_from_filename(filename)

    for row_values in df.head(20).iter_rows(named=False):
        for col_idx, cell_value in enumerate(row_values):
            if cell_value is None:
                continue

            cell_text = str(cell_value).lower()
            if any(key in cell_text for key in ["date", "trans", "dt", "post"]):
                for target_row in df.iter_rows(named=False):
                    try:
                        raw_date = str(target_row[col_idx])
                    except Exception:
                        continue

                    match = re.search(
                        r"(\d{4})[-/](\d{1,2})[-/](\d{1,2})|(\d{1,2})[-/](\d{1,2})[-/](\d{4})",
                        raw_date,
                    )
                    if match:
                        groups = match.groups()
                        if groups[0]:
                            parsed = valid_date_parts_fn(groups[0], groups[1], groups[2])
                        else:
                            parsed = valid_date_parts_fn(groups[5], groups[3], groups[4])
                        if parsed:
                            return parsed

    return extract_date_from_filename(filename)


signals = []
def process_candidate_file(
    item,
    stop_if_requested_fn=stop_if_requested,
    Path_arg=Path,
    parse_pos_filename_fn=parse_pos_filename,
    extract_date_from_filename_fn=extract_date_from_filename,
    re_arg=re,
    zipfile_arg=zipfile,
    config_arg=config,
    pl_arg=pl,
    io_arg=io,
    max_rows_arg=max_rows,
    max_branch_rows_arg=max_branch_rows,
    pdf_max_pages_arg=pdf_max_pages,
    PdfReader_arg=PdfReader,
    extract_date_from_text_fn=extract_date_from_text,
    extract_date_metadata_fn=extract_date_metadata,
    spreadsheet_extensions_arg=SUPPORTED_SPREADSHEET_EXTENSIONS,
    text_extensions_arg=SUPPORTED_TEXT_EXTENSIONS,
    read_xlsb_with_pyxlsb_fn=read_xlsb_with_pyxlsb,
):
        stop_if_requested_fn()

        file_path = None
        file_name = None

        try:
            file_path = Path_arg(item["file_path"])
            file_name = item.get("file_name") or file_path.name
            extension = str(item.get("extension") or file_path.suffix).lower()
            fn_lower = file_name.lower()

            pos_meta = parse_pos_filename_fn(file_name)

            if pos_meta:
                filename_date = (pos_meta["year"], pos_meta["month"], pos_meta["day"])
            else:
                filename_date = extract_date_from_filename_fn(file_name)

            signal = {
                "file_path": str(file_path),
                "file_name": file_name,
                "extension": extension,
                "content_type": (
                    "application/zip"
                    if extension == ".zip"
                    else "application/pdf"
                    if extension == ".pdf"
                    else "application/octet-stream"
                ),
                "fn_lower": fn_lower,
                "raw_numeric_blocks": re_arg.findall(r"\d{5,25}", file_name),
                "pos_meta": pos_meta,
                "is_epbdo": fn_lower.startswith("epbdo"),
                "is_pbdo": fn_lower.startswith("pbdo"),
                "prefer_pf": fn_lower.startswith("epbdo") or fn_lower.startswith("pbdo") or ("bdo" in fn_lower),
                "filename_date": filename_date,
                "content_date": filename_date,
                "content_digit_candidates": [],
                "branch_text_candidates": [],
                "zip_inner_filename_candidates": [],
                "zip_inner_content_digit_candidates": [],
                "is_encrypted": False,
            }

            if extension == ".zip":
                try:
                    with zipfile_arg.ZipFile(file_path, "r") as zip_file:
                        names = zip_file.namelist()

                        for inner in names:
                            if inner.endswith("/"):
                                continue

                            inner_name = Path_arg(inner).name
                            for block in re_arg.findall(r"\d{5,25}", inner_name):
                                signal["zip_inner_filename_candidates"].append({
                                    "inner_name": inner_name,
                                    "digits": block,
                                })

                        if config_arg.get("extract_zip_content_digits", True):
                            for inner in names:
                                if inner.endswith("/"):
                                    continue

                                inner_ext = Path_arg(inner).suffix.lower()
                                if inner_ext not in [".csv", ".txt"]:
                                    continue

                                try:
                                    data = zip_file.read(inner)
                                    df_inner = pl_arg.read_csv(
                                        io_arg.BytesIO(data),
                                        has_header=False,
                                        truncate_ragged_lines=True,
                                        ignore_errors=True,
                                        encoding="utf-8-lossy",
                                    )

                                    for row_idx, row_values in enumerate(df_inner.head(max_rows_arg).iter_rows(named=False)):
                                        for col_idx, cell_value in enumerate(row_values):
                                            if cell_value is None:
                                                continue

                                            digits = "".join(filter(str.isdigit, str(cell_value)))
                                            if 6 <= len(digits) <= 15:
                                                signal["zip_inner_content_digit_candidates"].append({
                                                    "inner_name": Path_arg(inner).name,
                                                    "row": row_idx + 1,
                                                    "col": col_idx + 1,
                                                    "digits": digits,
                                                })
                                except Exception:
                                    pass

                except zipfile_arg.BadZipFile:
                    signal["is_encrypted"] = True

            else:
                df = None
                pdf_text = ""
                is_encrypted = False

                try:
                    if extension in spreadsheet_extensions_arg:
                        try:
                            df = pl_arg.read_excel(
                                file_path,
                                engine="calamine",
                                has_header=False,
                                infer_schema_length=0,
                            )
                        except Exception:
                            if extension == ".xlsb":
                                df = read_xlsb_with_pyxlsb_fn(file_path)
                                signal["parser_fallback"] = "pyxlsb"
                            else:
                                raise
                    elif extension in text_extensions_arg:
                        df = pl_arg.read_csv(
                            file_path,
                            has_header=False,
                            truncate_ragged_lines=True,
                            ignore_errors=True,
                            encoding="utf-8-lossy",
                        )
                    elif extension == ".pdf":
                        reader = PdfReader_arg(str(file_path))
                        signal["pdf_page_count"] = len(reader.pages)
                        if reader.is_encrypted:
                            is_encrypted = True
                        else:
                            page_texts = []
                            for page_index, page in enumerate(reader.pages[:pdf_max_pages_arg]):
                                stop_if_requested_fn()
                                try:
                                    text = page.extract_text() or ""
                                except Exception:
                                    text = ""
                                if text:
                                    page_texts.append(text)
                                    if config_arg.get("extract_content_digits", True):
                                        for match in re_arg.finditer(r"\d{6,15}", text):
                                            signal["content_digit_candidates"].append({
                                                "page": page_index + 1,
                                                "digits": match.group(0),
                                            })
                                    if config_arg.get("extract_branch_text", True):
                                        for line in text.splitlines():
                                            cleaned_line = line.strip().lower()
                                            if len(cleaned_line) > 3:
                                                signal["branch_text_candidates"].append(cleaned_line[:240])
                            pdf_text = "\n".join(page_texts)
                            signal["content_date"] = extract_date_from_text_fn(pdf_text, file_name)
                except Exception as read_exc:
                    text = str(read_exc).lower()
                    if "password" in text or "encrypted" in text:
                        is_encrypted = True
                    else:
                        raise read_exc

                signal["is_encrypted"] = is_encrypted
                if not is_encrypted and extension == ".pdf":
                    signal["parser_status"] = "parsed" if pdf_text else "parsed_no_text"
                    if not pdf_text:
                        signal["parser_note"] = "PDF was readable, but no text was extracted. If this is a scanned PDF, OCR is required."
                elif not is_encrypted and df is None:
                    signal["parser_status"] = "no_parser_available"
                    signal["parser_note"] = f"No parser is configured for {extension}. Add it to spreadsheet_extensions or text_extensions if it is readable as Excel or text."
                elif not is_encrypted:
                    signal["parser_status"] = "parsed"

                if not is_encrypted and df is not None:
                    if config_arg.get("extract_content_digits", True):
                        for row_idx, row_values in enumerate(df.head(max_rows_arg).iter_rows(named=False)):
                            for col_idx, cell_value in enumerate(row_values):
                                if cell_value is None:
                                    continue

                                digits = "".join(filter(str.isdigit, str(cell_value)))
                                if 6 <= len(digits) <= 15:
                                    signal["content_digit_candidates"].append({
                                        "row": row_idx + 1,
                                        "col": col_idx + 1,
                                        "digits": digits,
                                    })

                    if config_arg.get("extract_branch_text", True):
                        for row_values in df.head(max_branch_rows_arg).iter_rows(named=False):
                            for cell_value in row_values:
                                if cell_value is None:
                                    continue

                                text = str(cell_value).strip().lower()
                                if len(text) > 3:
                                    signal["branch_text_candidates"].append(text)

                    signal["content_date"] = extract_date_metadata_fn(df, file_name)

            return signal, None

        except Exception as exc:
            return None, {
                "file_path": str(file_path) if file_path else item.get("file_path"),
                "file_name": file_name or item.get("file_name"),
                "error": str(exc),
            }


signals = []
error_files = []
total_candidates = len(candidate_files)
progress_batch_size = max(25, min(250, total_candidates // 10 or 25))
for index, item in enumerate(candidate_files, 1):
    signal, error = process_candidate_file(item)
    if signal:
        signals.append(signal)
    if error:
        error_files.append(error)
    if index == 1 or index == total_candidates or index % progress_batch_size == 0:
        log(
            f"Extracted {index}/{total_candidates} files - signals {len(signals)}, errors {len(error_files)}",
            level="info",
        )

signals_file = run_dir / "file_signals.json"
signal_errors_file = run_dir / "signal_errors.json"

signals_file.write_text(json.dumps(signals, ensure_ascii=False), encoding="utf-8")
signal_errors_file.write_text(json.dumps(error_files, ensure_ascii=False), encoding="utf-8")

log(f"Extracted signals: {len(signals)}, errors={len(error_files)}", level="info")

result = {
    "status": "signals_extracted",
    "signals_file": str(signals_file),
    "signal_errors_file": str(signal_errors_file),
    "total_candidates": total_candidates,
    "total_signals": len(signals),
    "total_errors": len(error_files),
    "sample_signals": group_examples_by_extension(signals),
    "sample_errors": group_examples_by_extension(error_files),
    "signal_extension_summary": group_examples_by_extension(signals),
    "error_extension_summary": group_examples_by_extension(error_files),
}

import re
import json
from decimal import Decimal, InvalidOperation
from pathlib import Path

globals().update({
    "re": re,
    "json": json,
    "Decimal": Decimal,
    "InvalidOperation": InvalidOperation,
    "Path": Path,
})

# =========================================================
# Load previous node outputs
# =========================================================

refs_result = context.get("Load Routing References", {}).get("result")
signals_result = context.get("Extract File Signals", {}).get("result")

if not refs_result:
    raise ValueError("Missing Load Routing References result")

if not signals_result:
    raise ValueError("Missing Extract File Signals result")

refs_payload = json.loads(Path(refs_result["refs_file"]).read_text(encoding="utf-8"))
signals = json.loads(Path(signals_result["signals_file"]).read_text(encoding="utf-8"))

validated = context.get("Validate Environment", {}).get("result", {})
run_dir = Path(validated["paths"]["run_dir"])

matrix_rows = refs_payload.get("matrix_rows", [])
pf_rows = refs_payload.get("pf_rows", [])
BANK_MATRIX_COLUMNS = refs_payload.get("bank_matrix_columns", [])

RULES_CONFIG = config.get("rules", {})


def is_enabled(rule_name, default=True, rules_config=RULES_CONFIG):
    return bool(rules_config.get(rule_name, default))


