# PBDO helpers
# =========================================================

def parse_pbdo_filename(file_name):
    stem = Path(file_name).stem.lower()

    match = re.match(
        r"^pbdo(\d{12})(\d{2})(\d{2})(\d{2})(db|dv|sv)([a-z0-9]*)$",
        stem,
        flags=re.IGNORECASE,
    )

    if not match:
        return None

    ref_area, month, day, year2, token, suffix = match.groups()

    month_int = int(month)
    day_int = int(day)

    if not (1 <= month_int <= 12):
        return None

    if not (1 <= day_int <= 31):
        return None

    token_map = {
        "db": "debit",
        "dv": "deferred",
        "sv": "straight",
    }

    reference_candidates = []
    reference_candidates.append(ref_area)
    reference_candidates.append(ref_area[:10])
    reference_candidates.append(ref_area.lstrip("0"))
    reference_candidates.append(ref_area[:10].lstrip("0"))

    clean_candidates = []
    for candidate in reference_candidates:
        candidate = str(candidate or "").strip()
        if candidate and candidate not in clean_candidates:
            clean_candidates.append(candidate)

    return {
        "ref_area": ref_area,
        "reference_candidates": clean_candidates,
        "year": f"20{year2}",
        "month": month.zfill(2),
        "day": day.zfill(2),
        "extra_path": token_map.get(token.lower(), ""),
        "suffix": suffix or "",
    }


def find_pbdo_matrix_match(reference_candidates):
    # PBDO should check BDO/PF matrix first.
    for candidate in reference_candidates:
        match = find_bank_by_numeric_id(candidate, prefer_pf=True)

        if match:
            _bank, company, branch, _extra_path, matrix_source = match
            return {
                "bank": "bdo",
                "company": company or "000",
                "branch": branch or "0000",
                "matrix_source": matrix_source,
                "matched_reference_id": candidate,
            }

    # Safety fallback:
    # If reference was placed in NonBDO matrix by mistake,
    # still use company/branch, but keep bank=bdo because filename says PBDO.
    for candidate in reference_candidates:
        match = find_bank_by_numeric_id(candidate, prefer_pf=False)

        if match:
            _bank, company, branch, _extra_path, matrix_source = match
            return {
                "bank": "bdo",
                "company": company or "000",
                "branch": branch or "0000",
                "matrix_source": f"nonbdo_reference_used_for_pbdo:{matrix_source}",
                "matched_reference_id": candidate,
            }

    return None


# =========================================================
# BDO filename helpers: SIBDO / SSBDO
# =========================================================

def parse_bdo_company_branch_date_filename(file_name):
    stem = Path(file_name).stem.lower()

    # Supports:
    # SIBDO101-0003051926
    # SSBDO101-0003051926
    #
    # prefix = sibdo or ssbdo
    # company = 101
    # branch = 0003
    # date = 051926 = MMDDYY
    match = re.match(
        r"^(sibdo|ssbdo)(\d{3})-(\d{4})(\d{2})(\d{2})(\d{2})$",
        stem,
        flags=re.IGNORECASE,
    )

    if not match:
        return None

    prefix, company, branch, month, day, year2 = match.groups()

    month_int = int(month)
    day_int = int(day)

    if not (1 <= month_int <= 12):
        return None

    if not (1 <= day_int <= 31):
        return None

    return {
        "prefix": prefix.lower(),
        "company": company.zfill(3),
        "branch": branch.zfill(4),
        "year": f"20{year2.zfill(2)}",
        "month": month.zfill(2),
        "day": day.zfill(2),
    }


