# TTL helpers
# =========================================================

def normalize_branch_text(value):
    text = str(value or "").lower()
    text = re.sub(r"[_\-.]+", " ", text)
    text = re.sub(r"\binitial\b", " ", text, flags=re.IGNORECASE)
    text = re.sub(r"\bttl\b", " ", text, flags=re.IGNORECASE)
    text = re.sub(r"\btotal\b", " ", text, flags=re.IGNORECASE)
    text = re.sub(r"\s+", " ", text).strip()
    return text


def extract_ttl_branch_candidates(file_name):
    stem = Path(file_name).stem

    cleaned = re.sub(
        r"(?i)\b(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t|tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+\d{1,2},?\s+20\d{2}\b",
        " ",
        stem,
    )

    cleaned = re.sub(r"\b\d{1,2}[.\-_]\d{1,2}[.\-_]\d{2,4}\b", " ", cleaned)

    parts = re.split(r"(?i)\bttl\b", cleaned)

    candidates = []

    for part in parts:
        candidate = normalize_branch_text(part)

        if candidate and len(candidate) > 1:
            candidates.append(candidate)

    alt = re.sub(r"(?i)\binitial\s*ttl\b", " ", cleaned)
    alt = normalize_branch_text(alt)

    if alt and len(alt) > 1:
        candidates.append(alt)

    unique = []

    for candidate in candidates:
        if candidate not in unique:
            unique.append(candidate)

    return unique


def extract_ttl_date_from_filename(file_name):
    stem = Path(file_name).stem

    month_map = {
        "jan": "01",
        "january": "01",
        "feb": "02",
        "february": "02",
        "mar": "03",
        "march": "03",
        "apr": "04",
        "april": "04",
        "may": "05",
        "jun": "06",
        "june": "06",
        "jul": "07",
        "july": "07",
        "aug": "08",
        "august": "08",
        "sep": "09",
        "sept": "09",
        "september": "09",
        "oct": "10",
        "october": "10",
        "nov": "11",
        "november": "11",
        "dec": "12",
        "december": "12",
    }

    text_date = re.search(
        r"(?i)\b(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t|tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+(\d{1,2}),?\s+(20\d{2})\b",
        stem,
    )

    if text_date:
        mon_text, day_text, year_text = text_date.groups()
        month = month_map.get(mon_text.lower())

        if month:
            return year_text, month, str(day_text).zfill(2)

    numeric_date = re.search(r"\b(\d{1,2})[.\-_](\d{1,2})[.\-_](\d{2,4})\b", stem)

    if numeric_date:
        mon, day, yr = numeric_date.groups()
        year = yr if len(yr) == 4 else f"20{yr.zfill(2)}"
        return year, str(mon).zfill(2), str(day).zfill(2)

    return None


def find_branch_codes_for_ttl(
    branch_candidates,
    matrix_rows_arg=matrix_rows,
    pf_rows_arg=pf_rows,
    get_pf_fields_fn=get_pf_fields,
):
    normalized_candidates = [
        normalize_branch_text(candidate)
        for candidate in branch_candidates
        if candidate
    ]

    for candidate in normalized_candidates:
        for row in matrix_rows_arg:
            matrix_branch = normalize_branch_text(row.get("branch name", ""))

            if matrix_branch == candidate:
                return (
                    row.get("company code", "000"),
                    row.get("branch code", "0000"),
                    candidate,
                    "nonbdo_branch_name_exact",
                )

    for candidate in normalized_candidates:
        for row in matrix_rows_arg:
            matrix_branch = normalize_branch_text(row.get("branch name", ""))

            if matrix_branch and (matrix_branch in candidate or candidate in matrix_branch):
                return (
                    row.get("company code", "000"),
                    row.get("branch code", "0000"),
                    candidate,
                    "nonbdo_branch_name_fuzzy",
                )

    for candidate in normalized_candidates:
        for row in pf_rows_arg:
            for key in ["branch name", "branchname", "branch", "store", "store name", "merchant name"]:
                if key not in row:
                    continue

                pf_branch = normalize_branch_text(row.get(key, ""))

                if pf_branch == candidate or (pf_branch and (pf_branch in candidate or candidate in pf_branch)):
                    company_code, branch_code, _ = get_pf_fields_fn(row)

                    return (
                        company_code or "000",
                        branch_code or "0000",
                        candidate,
                        "bdo_branch_name",
                    )

    return None


