def route_signal(
    signal,
    stop_if_requested_fn=stop_if_requested,
    Path_arg=Path,
    bool_arg=bool,
    str_arg=str,
    len_arg=len,
    is_enabled_fn=is_enabled,
    parse_pbdo_filename_fn=parse_pbdo_filename,
    find_pbdo_matrix_match_fn=find_pbdo_matrix_match,
    extract_ttl_branch_candidates_fn=extract_ttl_branch_candidates,
    extract_ttl_date_from_filename_fn=extract_ttl_date_from_filename,
    find_branch_codes_for_ttl_fn=find_branch_codes_for_ttl,
    normalize_bdo_reference_fn=normalize_bdo_reference,
    re_arg=re,
    find_bank_by_numeric_id_fn=find_bank_by_numeric_id,
    normalize_extra_path_fn=normalize_extra_path,
    find_bank_by_branch_text_fn=find_bank_by_branch_text,
    BANK_MATRIX_COLUMNS_arg=BANK_MATRIX_COLUMNS,
    matrix_rows_arg=matrix_rows,
    parse_bdo_company_branch_date_filename_fn=parse_bdo_company_branch_date_filename,
    normalize_branch_text_fn=normalize_branch_text,
):
        stop_if_requested_fn()

        try:
            unmatched_item = None
            routed_item = None
            file_name = signal.get("file_name", "")
            file_path = signal.get("file_path", "")
            fn_lower = signal.get("fn_lower") or file_name.lower()
            ext = signal.get("extension", "")
            prefer_pf = bool_arg(signal.get("prefer_pf"))
            is_epbdo = bool_arg(signal.get("is_epbdo"))
            pos_meta = signal.get("pos_meta")

            bank = "unknown_bank"
            company = "000"
            branch = "0000"
            extra_path = ""
            route_family = "bank"
            match_source = "None"
            matched_reference_id = "None"

            date_value = signal.get("content_date") or signal.get("filename_date")

            if date_value and len_arg(date_value) == 3:
                year, month, day = date_value
            else:
                year, month, day = "2026", "05", "15"

            # ---------------------------------------------------------
            # PRIORITY RULE 1: PBDO filename parse
            # ---------------------------------------------------------
            pbdo_locked = False

            if fn_lower.startswith("pbdo") and is_enabled_fn("pbdo_filename_rule", True):
                pbdo_meta = parse_pbdo_filename_fn(file_name)

                if pbdo_meta:
                    pbdo_locked = True

                    bank = "bdo"
                    route_family = "bank"
                    extra_path = pbdo_meta["extra_path"]

                    year = pbdo_meta["year"]
                    month = pbdo_meta["month"]
                    day = pbdo_meta["day"]

                    pbdo_match = find_pbdo_matrix_match_fn(pbdo_meta["reference_candidates"])

                    if pbdo_match:
                        company = pbdo_match["company"]
                        branch = pbdo_match["branch"]
                        matched_reference_id = pbdo_match["matched_reference_id"]
                        match_source = f"PBDO filename parse + matrix match [{pbdo_match['matrix_source']}]"
                    else:
                        company = "000"
                        branch = "0000"
                        matched_reference_id = pbdo_meta["ref_area"]
                        match_source = "PBDO filename parse + fallback company/branch"

            # ---------------------------------------------------------
            # PRIORITY RULE 2: TTL filename rule
            # ---------------------------------------------------------
            ttl_locked = False

            if (
                not pbdo_locked
                and "ttl" in fn_lower
                and is_enabled_fn("ttl_filename_rule", True)
            ):
                ttl_locked = True

                branch_candidates = extract_ttl_branch_candidates_fn(file_name)
                ttl_date = extract_ttl_date_from_filename_fn(file_name)
                ttl_branch_lookup = find_branch_codes_for_ttl_fn(branch_candidates)

                bank = "unknown_bank"
                route_family = "bank"
                extra_path = ""

                if ttl_branch_lookup:
                    company, branch, ttl_branch_name, ttl_source = ttl_branch_lookup
                    match_source = f"TTL filename rule [{ttl_source}]"
                    matched_reference_id = f"TTL branch: {ttl_branch_name}"
                else:
                    company = "000"
                    branch = "0000"
                    match_source = "TTL filename rule [branch not found]"
                    matched_reference_id = "TTL branch candidates: " + ", ".join(branch_candidates[:5])

                if ttl_date:
                    year, month, day = ttl_date

            # ---------------------------------------------------------
            # RULE 3: ZIP internal filename match
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and ext == ".zip"
                and bank == "unknown_bank"
                and is_enabled_fn("zip_internal_filename_match", True)
            ):
                for candidate in signal.get("zip_inner_filename_candidates", []):
                    raw_digits = candidate.get("digits", "")
                    pot_id = normalize_bdo_reference_fn(raw_digits) if prefer_pf else re_arg.sub(r"\D", "", raw_digits)

                    if not pot_id:
                        continue

                    if pot_id.startswith("202") and len_arg(pot_id) == 8:
                        continue

                    match = find_bank_by_numeric_id_fn(pot_id, prefer_pf=prefer_pf)

                    if match:
                        bank, company, branch, extra_path, matrix_source = match
                        extra_path = normalize_extra_path_fn(extra_path)
                        match_source = f"Zip internal filename [{matrix_source}]"
                        matched_reference_id = pot_id
                        break

            # ---------------------------------------------------------
            # RULE 4: ZIP internal content match
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and ext == ".zip"
                and bank == "unknown_bank"
