                    if not pot_id:
                        continue

                    if pot_id.startswith("202") and len_arg(pot_id) == 8:
                        continue

                    if not (5 <= len_arg(pot_id) <= 25):
                        continue

                    match = find_bank_by_numeric_id_fn(pot_id, prefer_pf=prefer_pf)

                    if match:
                        bank, company, branch, extra_path, matrix_source = match
                        extra_path = normalize_extra_path_fn(extra_path)
                        match_source = f"Filename string extraction [{matrix_source}]"
                        matched_reference_id = pot_id
                        break

            # ---------------------------------------------------------
            # RULE 7: Branch text match
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and bank == "unknown_bank"
                and not prefer_pf
                and not signal.get("is_encrypted")
                and is_enabled_fn("branch_text_match", True)
            ):
                bank_candidate, company_candidate, branch_candidate = find_bank_by_branch_text_fn(
                    signal.get("branch_text_candidates", [])
                )

                if bank_candidate != "unknown_bank":
                    bank = bank_candidate
                    company = company_candidate
                    branch = branch_candidate
                    match_source = "Branch name match"
                    matched_reference_id = "Branch Text Query"

            # ---------------------------------------------------------
            # RULE 8: BDO filename fallback
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
