                and is_enabled_fn("bdo_filename_fallback", True)
            ):
                bank = "bdo"
                match_source = "Filename indicates BDO fallback"
                matched_reference_id = "BDO filename indicator"

            # ---------------------------------------------------------
            # RULE 9: Bank keyword fallback
            # ---------------------------------------------------------
            elif (
                not pbdo_locked
                and not ttl_locked
                and bank == "unknown_bank"
                and is_enabled_fn("keyword_fallback", True)
            ):
                for bank_item in BANK_MATRIX_COLUMNS_arg:
                    bank_key = bank_item.get("bank", "")

                    if bank_key and bank_key in fn_lower:
                        bank = bank_key
                        extra_path = normalize_extra_path_fn(bank_item.get("extra_path", ""))
                        match_source = "Filename keyword fallback"
                        matched_reference_id = f"Keyword: {bank}"
                        break

            # ---------------------------------------------------------
            # RULE 10: MainSH SMAC special rule
            # Handles branch names like:
            # filename: MainSH_NEDSA_15-22.csv
            # matrix:   NORTH EDSA NEDSA
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and bank == "unknown_bank"
                and "mainsh" in fn_lower
                and is_enabled_fn("mainsh_smac_rule", True)
            ):
                bank = "smac"
                match_source = "MainSH SMAC rule"
                matched_reference_id = "MainSH"

                tokens = re_arg.split(r"[_ \-.]+", fn_lower)
                found_mainsh_branch = False

                for token in tokens:
                    if found_mainsh_branch:
                        break

                    token_clean = normalize_branch_text_fn(token)

                    if len_arg(token_clean) <= 2:
                        continue

                    if token_clean in ["mainsh", "main", "sh"]:
                        continue

                    # Skip pure date/number tokens like 15, 22, 2026.
                    if token_clean.isdigit():
                        continue

                    for row in matrix_rows_arg:
                        matrix_branch = normalize_branch_text_fn(row.get("branch name", ""))

                        if not matrix_branch:
                            continue

                        # Exact or contains match:
                        # "nedsa" == "nedsa"
                        # "nedsa" in "north edsa nedsa"
                        # "north edsa nedsa" in "nedsa" usually false, but safe.
                        if (
                            matrix_branch == token_clean
                            or token_clean in matrix_branch
                            or matrix_branch in token_clean
                        ):
