                    branch = bdo_name_meta["branch"]
                    month = bdo_name_meta["month"]
                    day = bdo_name_meta["day"]
                    year = bdo_name_meta["year"]
                    match_source = f"Filename {bdo_name_meta['prefix'].upper()} parse"
                    matched_reference_id = Path_arg(file_name).stem

                if is_epbdo:
                    epbdo_match = re_arg.search(r"epbdo(\d{3})(\d{2})(\d{2})(\d{2})", fn_lower)

                    if epbdo_match:
                        comp = epbdo_match.group(1)
                        mon = epbdo_match.group(2)
                        dayg = epbdo_match.group(3)
                        yr = epbdo_match.group(4)

                        company = str_arg(comp).zfill(3)
                        month = str_arg(mon).zfill(2)
                        day = str_arg(dayg).zfill(2)
                        year = f"20{str_arg(yr).zfill(2)}"
                        match_source = "Filename EPBDO parse"

                    token_match = re_arg.search(r"(sv|dv|db)(\d{1,})", fn_lower)

                    if not token_match:
                        token_match = re_arg.search(r"(sv|dv|db)", fn_lower)

                    if token_match:
                        token = token_match.group(1)

                        token_map = {
                            "sv": "straight",
                            "dv": "deferred",
                            "db": "debit",
                        }

                        extra_path = token_map.get(token, extra_path)

                        if len_arg(token_match.groups()) >= 2 and token_match.group(2):
                            digits_after = re_arg.sub(r"\D", "", token_match.group(2))

                            if len_arg(digits_after) >= 4:
                                branch = str_arg(digits_after[:4]).zfill(4)
                            else:
                                branch = str_arg(digits_after).zfill(4)

                        match_source = f"Filename token {token.upper()} branch override"

            # ---------------------------------------------------------
