refs_result = context.get("Load Routing References", {}).get("result")
signals_result = context.get("Extract File Signals", {}).get("result")

if not refs_result:
    raise ValueError("Missing Load Routing References result")

if not signals_result:
    raise ValueError("Missing Extract File Signals result")

refs_payload = json.loads(Path(refs_result["refs_file"]).read_text(encoding="utf-8"))
signals = json.loads(Path(signals_result["signals_file"]).read_text(encoding="utf-8"))

validated = context.get("Validate Environment", {}).get("result", {})
run_dir = Path(validated["paths"]["run_dir"])

matrix_rows = refs_payload.get("matrix_rows", [])
pf_rows = refs_payload.get("pf_rows", [])
BANK_MATRIX_COLUMNS = refs_payload.get("bank_matrix_columns", [])

RULES_CONFIG = config.get("rules", {})


def is_enabled(rule_name, default=True, rules_config=RULES_CONFIG):
    return bool(rules_config.get(rule_name, default))


# =========================================================
# Generic helpers
# =========================================================

def normalize_extra_path(path_val):
    if not path_val:
        return ""

    pv = str(path_val).lower().strip()

    if "debit" in pv or pv == "db":
        return "debit"

    if "defer" in pv or pv == "dv" or "deferred" in pv:
        return "deferred"

    if "straight" in pv or pv == "sv":
        return "straight"

    return pv.replace(" ", "_")


def normalize_bdo_reference(raw_digits):
    digits = re.sub(r"\D", "", str(raw_digits).strip())

    if len(digits) > 12:
        return digits[:12]

    return digits


def normalize_numeric_token(value, re_arg=re, Decimal_arg=Decimal, InvalidOperation_arg=InvalidOperation):
    text = str(value or "").strip()

    if not text:
        return ""

    # Excel may expose IDs as 100301923.0 or 1.00301923E8.
    if re_arg.fullmatch(r"\d+(?:\.0+)?", text):
        return text.split(".")[0]

    if re_arg.fullmatch(r"\d+(?:\.\d+)?[eE][+-]?\d+", text):
        try:
            decimal_value = Decimal_arg(text)
            if decimal_value == decimal_value.to_integral_value():
                return format(decimal_value.quantize(Decimal_arg(1)), "f")
        except (InvalidOperation_arg, ValueError):
            pass

    return re_arg.sub(r"\D", "", text)


def norm_digits(value, normalize_numeric_token_fn=normalize_numeric_token):
    digits = normalize_numeric_token_fn(value)
    return digits.lstrip("0") or "0"


def numeric_variants(value, re_arg=re, normalize_numeric_token_fn=normalize_numeric_token, norm_digits_fn=norm_digits):
    clean = normalize_numeric_token_fn(value)

    if not clean:
        return []

    variants = []

    def add(candidate):
        candidate = normalize_numeric_token_fn(candidate)
        if candidate and candidate not in variants:
            variants.append(candidate)
        normalized = norm_digits_fn(candidate)
        if normalized and normalized not in variants:
            variants.append(normalized)

    add(clean)

    # MID/reference values can be left-padded before the actual matrix ID.
    for width in range(5, min(25, len(clean)) + 1):
        add(clean[-width:])

    if clean.startswith("00"):
        add(clean[2:])
    if clean.startswith("0"):
        add(clean[1:])

    return variants


def extract_cell_ids(cell_value, re_arg=re, normalize_numeric_token_fn=normalize_numeric_token):
    if cell_value is None:
        return []

    text = str(cell_value).strip()

    if not text:
        return []

    ids = []

    def add(candidate):
        candidate = normalize_numeric_token_fn(candidate)
        if 5 <= len(candidate) <= 25 and candidate not in ids:
            ids.append(candidate)

    for chunk in re_arg.split(r"[,;\n\r]+", text):
        chunk = chunk.strip()

        if not chunk:
            continue

        add(chunk)

        for match in re_arg.findall(r"\d+(?:\.\d+)?[eE][+-]?\d+|\d{5,25}(?:\.0+)?", chunk):
            add(match)

    if ids:
        return ids

    for match in re_arg.findall(r"\d+(?:\.\d+)?[eE][+-]?\d+|\d{5,25}(?:\.0+)?", text):
        add(match)

    return ids


def get_pf_fields(row, re_arg=re):
    company = None
    branch = None
    path1 = row.get("path1") or ""

    combined = None

    for key in ["code", "company-branch", "companybranch", "company_branch", "branchcode_combined"]:
        if key in row and row.get(key) not in (None, ""):
            combined = row.get(key)
            break

    if combined:
        text = str(combined).strip()
        parts = [part for part in re_arg.split(r"\D+", text) if part]

        if len(parts) >= 2:
            company = parts[0]
            branch = parts[1]
        else:
            digits = re_arg.sub(r"\D", "", text)
            if len(digits) >= 7:
                company = digits[:3]
                branch = digits[-4:]

    if not branch:
        for key in ["branchcode", "branch code", "branch_code"]:
            if key in row and row.get(key) not in (None, ""):
                branch = row.get(key)
                break

    if not company:
        for key in ["company code", "company", "companycode"]:
            if key in row and row.get(key) not in (None, ""):
                company = row.get(key)
                break

    if company is not None:
        company = re_arg.sub(r"\D", "", str(company).strip()).zfill(3)

    if branch is not None:
        branch = re_arg.sub(r"\D", "", str(branch).strip()).zfill(4)

    return company, branch, path1



def build_numeric_lookup_maps(
    matrix_rows_arg=matrix_rows,
    pf_rows_arg=pf_rows,
    bank_matrix_columns_arg=BANK_MATRIX_COLUMNS,
    extract_cell_ids_fn=extract_cell_ids,
    norm_digits_fn=norm_digits,
    get_pf_fields_fn=get_pf_fields,
):
    # Preserve the original matching order: bank column -> matrix row -> cell id.
    # Only index the exact normalized matrix cell IDs. Candidate variants are still
    # generated at lookup time, which keeps behavior aligned with the old loop.
    nonbdo_lookup = {}
    for item in bank_matrix_columns_arg:
        bank_col = item.get("col")
        bank_name = item.get("bank")
        if not bank_col:
            continue
        for row in matrix_rows_arg:
            raw_cell_val = row.get(bank_col)
            if raw_cell_val in (None, ""):
                continue
            for cell_id in extract_cell_ids_fn(raw_cell_val):
                key = norm_digits_fn(cell_id)
                if key and key not in nonbdo_lookup:
                    nonbdo_lookup[key] = (
                        bank_name,
                        row.get("company code", "000"),
                        row.get("branch code", "0000"),
                        item.get("extra_path", ""),
                        "branch_matrix",
                    )

    pf_lookup = {}
    pf_id_cols = ["ref1", "ref2g", "ref2r", "ref2p", "ref2q"]
    for row in pf_rows_arg:
        for col in pf_id_cols:
            raw_cell_val = row.get(col)
            if raw_cell_val in (None, ""):
                continue
            for cell_id in extract_cell_ids_fn(raw_cell_val):
                key = norm_digits_fn(cell_id)
                if key and key not in pf_lookup:
                    company, branch, path1 = get_pf_fields_fn(row)
                    pf_lookup[key] = (
                        "bdo",
                        company or "000",
                        branch or "0000",
                        str(path1).strip().lower(),
                        "pf_generation",
                    )
    return nonbdo_lookup, pf_lookup


NONBDO_NUMERIC_LOOKUP, PF_NUMERIC_LOOKUP = build_numeric_lookup_maps()
log(
    f"Built routing lookup maps: nonbdo={len(NONBDO_NUMERIC_LOOKUP)}, pf={len(PF_NUMERIC_LOOKUP)}",
    level="info",
)


def find_bank_by_numeric_id(
    raw_digits,
    prefer_pf=False,
    matrix_rows_arg=matrix_rows,
    pf_rows_arg=pf_rows,
    bank_matrix_columns_arg=BANK_MATRIX_COLUMNS,
    re_arg=re,
    norm_digits_fn=norm_digits,
    extract_cell_ids_fn=extract_cell_ids,
    get_pf_fields_fn=get_pf_fields,
    numeric_variants_fn=numeric_variants,
    normalize_numeric_token_fn=normalize_numeric_token,
    nonbdo_lookup_arg=NONBDO_NUMERIC_LOOKUP,
    pf_lookup_arg=PF_NUMERIC_LOOKUP,
):
    if not raw_digits:
        return None

    clean_id = normalize_numeric_token_fn(raw_digits)

    if not clean_id:
        return None

    branch_candidates = set(numeric_variants_fn(clean_id))
    pf_candidates = set(numeric_variants_fn(clean_id))

    if len(clean_id) > 12:
        pf_candidates.add(clean_id[:12])

    if len(clean_id) > 10:
        pf_candidates.add(clean_id[:10])

    if len(clean_id) > 6:
        pf_candidates.add(clean_id[:-6])

    if len(clean_id) > 8:
        pf_candidates.add(clean_id[:-8])

    pf_candidates = {
        candidate
        for candidate in pf_candidates
        if candidate and len(re_arg.sub(r"\D", "", candidate)) <= 12
    }

    # NonBDO matrix matching, using a lookup map built in the same priority order
    # as the original row-by-row scan.
    if not prefer_pf:
        for candidate in branch_candidates:
            match = nonbdo_lookup_arg.get(norm_digits_fn(candidate))
            if match:
                return match

    # BDO / PF matrix matching, using exact normalized reference IDs.
    for candidate in pf_candidates:
        match = pf_lookup_arg.get(norm_digits_fn(candidate))
        if match:
            return match

    return None

def find_bank_by_branch_text(
    branch_text_candidates,
    matrix_rows_arg=matrix_rows,
    bank_matrix_columns_arg=BANK_MATRIX_COLUMNS,
):
    if not matrix_rows_arg:
        return "unknown_bank", "000", "0000"

    for text in branch_text_candidates:
        cell_clean = str(text).strip().lower()

        if len(cell_clean) <= 3:
            continue

        for row in matrix_rows_arg:
            matrix_branch_name = str(row.get("branch name", "")).strip().lower()

            if matrix_branch_name == cell_clean:
                detected_bank = "unknown_bank"

                for item in bank_matrix_columns_arg:
                    value = str(row.get(item["col"], "") or "").strip()

                    if value:
                        detected_bank = item["bank"]
                        break

                return (
                    detected_bank,
                    row.get("company code", "000"),
                    row.get("branch code", "0000"),
                )

    return "unknown_bank", "000", "0000"


# =========================================================
# PBDO helpers
# =========================================================

def parse_pbdo_filename(file_name):
    stem = Path(file_name).stem.lower()

    match = re.match(
        r"^pbdo(\d{12})(\d{2})(\d{2})(\d{2})(db|dv|sv)([a-z0-9]*)$",
        stem,
        flags=re.IGNORECASE,
    )

    if not match:
        return None

    ref_area, month, day, year2, token, suffix = match.groups()

    month_int = int(month)
    day_int = int(day)

    if not (1 <= month_int <= 12):
        return None

    if not (1 <= day_int <= 31):
        return None

    token_map = {
        "db": "debit",
        "dv": "deferred",
        "sv": "straight",
    }

    reference_candidates = []
    reference_candidates.append(ref_area)
    reference_candidates.append(ref_area[:10])
    reference_candidates.append(ref_area.lstrip("0"))
    reference_candidates.append(ref_area[:10].lstrip("0"))

    clean_candidates = []
    for candidate in reference_candidates:
        candidate = str(candidate or "").strip()
        if candidate and candidate not in clean_candidates:
            clean_candidates.append(candidate)

    return {
        "ref_area": ref_area,
        "reference_candidates": clean_candidates,
        "year": f"20{year2}",
        "month": month.zfill(2),
        "day": day.zfill(2),
        "extra_path": token_map.get(token.lower(), ""),
        "suffix": suffix or "",
    }


def find_pbdo_matrix_match(reference_candidates):
    # PBDO should check BDO/PF matrix first.
    for candidate in reference_candidates:
        match = find_bank_by_numeric_id(candidate, prefer_pf=True)

        if match:
            _bank, company, branch, _extra_path, matrix_source = match
            return {
                "bank": "bdo",
                "company": company or "000",
                "branch": branch or "0000",
                "matrix_source": matrix_source,
                "matched_reference_id": candidate,
            }

    # Safety fallback:
    # If reference was placed in NonBDO matrix by mistake,
    # still use company/branch, but keep bank=bdo because filename says PBDO.
    for candidate in reference_candidates:
        match = find_bank_by_numeric_id(candidate, prefer_pf=False)

        if match:
            _bank, company, branch, _extra_path, matrix_source = match
            return {
                "bank": "bdo",
                "company": company or "000",
                "branch": branch or "0000",
                "matrix_source": f"nonbdo_reference_used_for_pbdo:{matrix_source}",
                "matched_reference_id": candidate,
            }

    return None


# =========================================================
# BDO filename helpers: SIBDO / SSBDO
# =========================================================

def parse_bdo_company_branch_date_filename(file_name):
    stem = Path(file_name).stem.lower()

    # Supports:
    # SIBDO101-0003051926
    # SSBDO101-0003051926
    #
    # prefix = sibdo or ssbdo
    # company = 101
    # branch = 0003
    # date = 051926 = MMDDYY
    match = re.match(
        r"^(sibdo|ssbdo)(\d{3})-(\d{4})(\d{2})(\d{2})(\d{2})$",
        stem,
        flags=re.IGNORECASE,
    )

    if not match:
        return None

    prefix, company, branch, month, day, year2 = match.groups()

    month_int = int(month)
    day_int = int(day)

    if not (1 <= month_int <= 12):
        return None

    if not (1 <= day_int <= 31):
        return None

    return {
        "prefix": prefix.lower(),
        "company": company.zfill(3),
        "branch": branch.zfill(4),
        "year": f"20{year2.zfill(2)}",
        "month": month.zfill(2),
        "day": day.zfill(2),
    }


# =========================================================
# TTL helpers
# =========================================================

def normalize_branch_text(value):
    text = str(value or "").lower()
    text = re.sub(r"[_\-.]+", " ", text)
    text = re.sub(r"\binitial\b", " ", text, flags=re.IGNORECASE)
    text = re.sub(r"\bttl\b", " ", text, flags=re.IGNORECASE)
    text = re.sub(r"\btotal\b", " ", text, flags=re.IGNORECASE)
    text = re.sub(r"\s+", " ", text).strip()
    return text


def extract_ttl_branch_candidates(file_name):
    stem = Path(file_name).stem

    cleaned = re.sub(
        r"(?i)\b(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t|tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+\d{1,2},?\s+20\d{2}\b",
        " ",
        stem,
    )

    cleaned = re.sub(r"\b\d{1,2}[.\-_]\d{1,2}[.\-_]\d{2,4}\b", " ", cleaned)

    parts = re.split(r"(?i)\bttl\b", cleaned)

    candidates = []

    for part in parts:
        candidate = normalize_branch_text(part)

        if candidate and len(candidate) > 1:
            candidates.append(candidate)

    alt = re.sub(r"(?i)\binitial\s*ttl\b", " ", cleaned)
    alt = normalize_branch_text(alt)

    if alt and len(alt) > 1:
        candidates.append(alt)

    unique = []

    for candidate in candidates:
        if candidate not in unique:
            unique.append(candidate)

    return unique


def extract_ttl_date_from_filename(file_name):
    stem = Path(file_name).stem

    month_map = {
        "jan": "01",
        "january": "01",
        "feb": "02",
        "february": "02",
        "mar": "03",
        "march": "03",
        "apr": "04",
        "april": "04",
        "may": "05",
        "jun": "06",
        "june": "06",
        "jul": "07",
        "july": "07",
        "aug": "08",
        "august": "08",
        "sep": "09",
        "sept": "09",
        "september": "09",
        "oct": "10",
        "october": "10",
        "nov": "11",
        "november": "11",
        "dec": "12",
        "december": "12",
    }

    text_date = re.search(
        r"(?i)\b(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:t|tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\s+(\d{1,2}),?\s+(20\d{2})\b",
        stem,
    )

    if text_date:
        mon_text, day_text, year_text = text_date.groups()
        month = month_map.get(mon_text.lower())

        if month:
            return year_text, month, str(day_text).zfill(2)

    numeric_date = re.search(r"\b(\d{1,2})[.\-_](\d{1,2})[.\-_](\d{2,4})\b", stem)

    if numeric_date:
        mon, day, yr = numeric_date.groups()
        year = yr if len(yr) == 4 else f"20{yr.zfill(2)}"
        return year, str(mon).zfill(2), str(day).zfill(2)

    return None


def find_branch_codes_for_ttl(
    branch_candidates,
    matrix_rows_arg=matrix_rows,
    pf_rows_arg=pf_rows,
    get_pf_fields_fn=get_pf_fields,
):
    normalized_candidates = [
        normalize_branch_text(candidate)
        for candidate in branch_candidates
        if candidate
    ]

    for candidate in normalized_candidates:
        for row in matrix_rows_arg:
            matrix_branch = normalize_branch_text(row.get("branch name", ""))

            if matrix_branch == candidate:
                return (
                    row.get("company code", "000"),
                    row.get("branch code", "0000"),
                    candidate,
                    "nonbdo_branch_name_exact",
                )

    for candidate in normalized_candidates:
        for row in matrix_rows_arg:
            matrix_branch = normalize_branch_text(row.get("branch name", ""))

            if matrix_branch and (matrix_branch in candidate or candidate in matrix_branch):
                return (
                    row.get("company code", "000"),
                    row.get("branch code", "0000"),
                    candidate,
                    "nonbdo_branch_name_fuzzy",
                )

    for candidate in normalized_candidates:
        for row in pf_rows_arg:
            for key in ["branch name", "branchname", "branch", "store", "store name", "merchant name"]:
                if key not in row:
                    continue

                pf_branch = normalize_branch_text(row.get(key, ""))

                if pf_branch == candidate or (pf_branch and (pf_branch in candidate or candidate in pf_branch)):
                    company_code, branch_code, _ = get_pf_fields_fn(row)

                    return (
                        company_code or "000",
                        branch_code or "0000",
                        candidate,
                        "bdo_branch_name",
                    )

    return None


globals().update({
    "is_enabled": is_enabled,
    "normalize_extra_path": normalize_extra_path,
    "normalize_bdo_reference": normalize_bdo_reference,
    "norm_digits": norm_digits,
    "extract_cell_ids": extract_cell_ids,
    "get_pf_fields": get_pf_fields,
    "find_bank_by_numeric_id": find_bank_by_numeric_id,
    "find_bank_by_branch_text": find_bank_by_branch_text,
    "parse_pbdo_filename": parse_pbdo_filename,
    "find_pbdo_matrix_match": find_pbdo_matrix_match,
    "parse_bdo_company_branch_date_filename": parse_bdo_company_branch_date_filename,
    "normalize_branch_text": normalize_branch_text,
    "extract_ttl_branch_candidates": extract_ttl_branch_candidates,
    "extract_ttl_date_from_filename": extract_ttl_date_from_filename,
    "find_branch_codes_for_ttl": find_branch_codes_for_ttl,
})


# =========================================================
# Routing loop
# =========================================================

def route_signal(
    signal,
    stop_if_requested_fn=stop_if_requested,
    Path_arg=Path,
    bool_arg=bool,
    str_arg=str,
    len_arg=len,
    is_enabled_fn=is_enabled,
    parse_pbdo_filename_fn=parse_pbdo_filename,
    find_pbdo_matrix_match_fn=find_pbdo_matrix_match,
    extract_ttl_branch_candidates_fn=extract_ttl_branch_candidates,
    extract_ttl_date_from_filename_fn=extract_ttl_date_from_filename,
    find_branch_codes_for_ttl_fn=find_branch_codes_for_ttl,
    normalize_bdo_reference_fn=normalize_bdo_reference,
    re_arg=re,
    find_bank_by_numeric_id_fn=find_bank_by_numeric_id,
    normalize_extra_path_fn=normalize_extra_path,
    find_bank_by_branch_text_fn=find_bank_by_branch_text,
    BANK_MATRIX_COLUMNS_arg=BANK_MATRIX_COLUMNS,
    matrix_rows_arg=matrix_rows,
    parse_bdo_company_branch_date_filename_fn=parse_bdo_company_branch_date_filename,
    normalize_branch_text_fn=normalize_branch_text,
):
        stop_if_requested_fn()

        try:
            unmatched_item = None
            routed_item = None
            file_name = signal.get("file_name", "")
            file_path = signal.get("file_path", "")
            fn_lower = signal.get("fn_lower") or file_name.lower()
            ext = signal.get("extension", "")
            prefer_pf = bool_arg(signal.get("prefer_pf"))
            is_epbdo = bool_arg(signal.get("is_epbdo"))
            pos_meta = signal.get("pos_meta")

            bank = "unknown_bank"
            company = "000"
            branch = "0000"
            extra_path = ""
            route_family = "bank"
            match_source = "None"
            matched_reference_id = "None"

            date_value = signal.get("content_date") or signal.get("filename_date")

            if date_value and len_arg(date_value) == 3:
                year, month, day = date_value
            else:
                year, month, day = "2026", "05", "15"

            # ---------------------------------------------------------
            # PRIORITY RULE 1: PBDO filename parse
            # ---------------------------------------------------------
            pbdo_locked = False

            if fn_lower.startswith("pbdo") and is_enabled_fn("pbdo_filename_rule", True):
                pbdo_meta = parse_pbdo_filename_fn(file_name)

                if pbdo_meta:
                    pbdo_locked = True

                    bank = "bdo"
                    route_family = "bank"
                    extra_path = pbdo_meta["extra_path"]

                    year = pbdo_meta["year"]
                    month = pbdo_meta["month"]
                    day = pbdo_meta["day"]

                    pbdo_match = find_pbdo_matrix_match_fn(pbdo_meta["reference_candidates"])

                    if pbdo_match:
                        company = pbdo_match["company"]
                        branch = pbdo_match["branch"]
                        matched_reference_id = pbdo_match["matched_reference_id"]
                        match_source = f"PBDO filename parse + matrix match [{pbdo_match['matrix_source']}]"
                    else:
                        company = "000"
                        branch = "0000"
                        matched_reference_id = pbdo_meta["ref_area"]
                        match_source = "PBDO filename parse + fallback company/branch"

            # ---------------------------------------------------------
            # PRIORITY RULE 2: TTL filename rule
            # ---------------------------------------------------------
            ttl_locked = False

            if (
                not pbdo_locked
                and "ttl" in fn_lower
                and is_enabled_fn("ttl_filename_rule", True)
            ):
                ttl_locked = True

                branch_candidates = extract_ttl_branch_candidates_fn(file_name)
                ttl_date = extract_ttl_date_from_filename_fn(file_name)
                ttl_branch_lookup = find_branch_codes_for_ttl_fn(branch_candidates)

                bank = "unknown_bank"
                route_family = "bank"
                extra_path = ""

                if ttl_branch_lookup:
                    company, branch, ttl_branch_name, ttl_source = ttl_branch_lookup
                    match_source = f"TTL filename rule [{ttl_source}]"
                    matched_reference_id = f"TTL branch: {ttl_branch_name}"
                else:
                    company = "000"
                    branch = "0000"
                    match_source = "TTL filename rule [branch not found]"
                    matched_reference_id = "TTL branch candidates: " + ", ".join(branch_candidates[:5])

                if ttl_date:
                    year, month, day = ttl_date

            # ---------------------------------------------------------
            # RULE 3: ZIP internal filename match
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and ext == ".zip"
                and bank == "unknown_bank"
                and is_enabled_fn("zip_internal_filename_match", True)
            ):
                for candidate in signal.get("zip_inner_filename_candidates", []):
                    raw_digits = candidate.get("digits", "")
                    pot_id = normalize_bdo_reference_fn(raw_digits) if prefer_pf else re_arg.sub(r"\D", "", raw_digits)

                    if not pot_id:
                        continue

                    if pot_id.startswith("202") and len_arg(pot_id) == 8:
                        continue

                    match = find_bank_by_numeric_id_fn(pot_id, prefer_pf=prefer_pf)

                    if match:
                        bank, company, branch, extra_path, matrix_source = match
                        extra_path = normalize_extra_path_fn(extra_path)
                        match_source = f"Zip internal filename [{matrix_source}]"
                        matched_reference_id = pot_id
                        break

            # ---------------------------------------------------------
            # RULE 4: ZIP internal content match
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and ext == ".zip"
                and bank == "unknown_bank"
                and is_enabled_fn("zip_internal_content_match", True)
            ):
                for candidate in signal.get("zip_inner_content_digit_candidates", []):
                    raw_digits = candidate.get("digits", "")
                    pot_id = normalize_bdo_reference_fn(raw_digits) if prefer_pf else re_arg.sub(r"\D", "", raw_digits)

                    if not pot_id:
                        continue

                    if pot_id.startswith("202") and len_arg(pot_id) == 8:
                        continue

                    match = find_bank_by_numeric_id_fn(pot_id, prefer_pf=prefer_pf)

                    if match:
                        bank, company, branch, extra_path, matrix_source = match
                        extra_path = normalize_extra_path_fn(extra_path)
                        match_source = f"Zip internal file data [{matrix_source}]"
                        matched_reference_id = pot_id
                        break

            # ---------------------------------------------------------
            # RULE 5: Inside file content match
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and ext != ".zip"
                and bank == "unknown_bank"
                and is_enabled_fn("inside_file_data_match", True)
            ):
                for candidate in signal.get("content_digit_candidates", []):
                    raw_digits = candidate.get("digits", "")
                    pot_id = normalize_bdo_reference_fn(raw_digits) if prefer_pf else re_arg.sub(r"\D", "", raw_digits)

                    if not pot_id:
                        continue

                    if pot_id.startswith("202") and len_arg(pot_id) == 8:
                        continue

                    match = find_bank_by_numeric_id_fn(pot_id, prefer_pf=prefer_pf)

                    if match:
                        bank, company, branch, extra_path, matrix_source = match
                        extra_path = normalize_extra_path_fn(extra_path)
                        match_source = f"Inside file data [{matrix_source}]"
                        matched_reference_id = pot_id
                        break

            # ---------------------------------------------------------
            # RULE 6: Filename MID/reference match
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and bank == "unknown_bank"
                and is_enabled_fn("filename_mid_match", True)
            ):
                for raw_block in signal.get("raw_numeric_blocks", []):
                    pot_id = normalize_bdo_reference_fn(raw_block) if prefer_pf else re_arg.sub(r"\D", "", raw_block)

                    if not pot_id:
                        continue

                    if pot_id.startswith("202") and len_arg(pot_id) == 8:
                        continue

                    if not (5 <= len_arg(pot_id) <= 25):
                        continue

                    match = find_bank_by_numeric_id_fn(pot_id, prefer_pf=prefer_pf)

                    if match:
                        bank, company, branch, extra_path, matrix_source = match
                        extra_path = normalize_extra_path_fn(extra_path)
                        match_source = f"Filename string extraction [{matrix_source}]"
                        matched_reference_id = pot_id
                        break

            # ---------------------------------------------------------
            # RULE 7: Branch text match
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and bank == "unknown_bank"
                and not prefer_pf
                and not signal.get("is_encrypted")
                and is_enabled_fn("branch_text_match", True)
            ):
                bank_candidate, company_candidate, branch_candidate = find_bank_by_branch_text_fn(
                    signal.get("branch_text_candidates", [])
                )

                if bank_candidate != "unknown_bank":
                    bank = bank_candidate
                    company = company_candidate
                    branch = branch_candidate
                    match_source = "Branch name match"
                    matched_reference_id = "Branch Text Query"

            # ---------------------------------------------------------
            # RULE 8: BDO filename fallback
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and bank == "unknown_bank"
                and prefer_pf
                and is_enabled_fn("bdo_filename_fallback", True)
            ):
                bank = "bdo"
                match_source = "Filename indicates BDO fallback"
                matched_reference_id = "BDO filename indicator"

            # ---------------------------------------------------------
            # RULE 9: Bank keyword fallback
            # ---------------------------------------------------------
            elif (
                not pbdo_locked
                and not ttl_locked
                and bank == "unknown_bank"
                and is_enabled_fn("keyword_fallback", True)
            ):
                for bank_item in BANK_MATRIX_COLUMNS_arg:
                    bank_key = bank_item.get("bank", "")

                    if bank_key and bank_key in fn_lower:
                        bank = bank_key
                        extra_path = normalize_extra_path_fn(bank_item.get("extra_path", ""))
                        match_source = "Filename keyword fallback"
                        matched_reference_id = f"Keyword: {bank}"
                        break

            # ---------------------------------------------------------
            # RULE 10: MainSH SMAC special rule
            # Handles branch names like:
            # filename: MainSH_NEDSA_15-22.csv
            # matrix:   NORTH EDSA NEDSA
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and bank == "unknown_bank"
                and "mainsh" in fn_lower
                and is_enabled_fn("mainsh_smac_rule", True)
            ):
                bank = "smac"
                match_source = "MainSH SMAC rule"
                matched_reference_id = "MainSH"

                tokens = re_arg.split(r"[_ \-.]+", fn_lower)
                found_mainsh_branch = False

                for token in tokens:
                    if found_mainsh_branch:
                        break

                    token_clean = normalize_branch_text_fn(token)

                    if len_arg(token_clean) <= 2:
                        continue

                    if token_clean in ["mainsh", "main", "sh"]:
                        continue

                    # Skip pure date/number tokens like 15, 22, 2026.
                    if token_clean.isdigit():
                        continue

                    for row in matrix_rows_arg:
                        matrix_branch = normalize_branch_text_fn(row.get("branch name", ""))

                        if not matrix_branch:
                            continue

                        # Exact or contains match:
                        # "nedsa" == "nedsa"
                        # "nedsa" in "north edsa nedsa"
                        # "north edsa nedsa" in "nedsa" usually false, but safe.
                        if (
                            matrix_branch == token_clean
                            or token_clean in matrix_branch
                            or matrix_branch in token_clean
                        ):
                            company = str_arg(row.get("company code", "000")).zfill(3)
                            branch = str_arg(row.get("branch code", "0000")).zfill(4)
                            match_source = f"MainSH SMAC rule + branch lookup ({token_clean} matched {matrix_branch})"
                            matched_reference_id = matrix_branch
                            found_mainsh_branch = True
                            break

            # ---------------------------------------------------------
            # RULE 11: POS filename override
            # ---------------------------------------------------------
            if pos_meta and is_enabled_fn("pos_filename_override", True):
                route_family = "pos"
                bank = "pos"
                company = pos_meta["company"]
                branch = pos_meta["branch"]
                year = pos_meta["year"]
                month = pos_meta["month"]
                day = pos_meta["day"]
                matched_reference_id = Path_arg(file_name).stem
                match_source = f"Filename POS {pos_meta['family'].upper()} parse"

            # ---------------------------------------------------------
            # RULE 12: BDO filename overrides
            # SIBDO and SSBDO now use the same parser.
            # ---------------------------------------------------------
            if (
                not pbdo_locked
                and not ttl_locked
                and str_arg(bank).lower() == "bdo"
                and is_enabled_fn("bdo_filename_overrides", True)
            ):
                bdo_name_meta = parse_bdo_company_branch_date_filename_fn(file_name)

                if bdo_name_meta:
                    company = bdo_name_meta["company"]
                    branch = bdo_name_meta["branch"]
                    month = bdo_name_meta["month"]
                    day = bdo_name_meta["day"]
                    year = bdo_name_meta["year"]
                    match_source = f"Filename {bdo_name_meta['prefix'].upper()} parse"
                    matched_reference_id = Path_arg(file_name).stem

                if is_epbdo:
                    epbdo_match = re_arg.search(r"epbdo(\d{3})(\d{2})(\d{2})(\d{2})", fn_lower)

                    if epbdo_match:
                        comp = epbdo_match.group(1)
                        mon = epbdo_match.group(2)
                        dayg = epbdo_match.group(3)
                        yr = epbdo_match.group(4)

                        company = str_arg(comp).zfill(3)
                        month = str_arg(mon).zfill(2)
                        day = str_arg(dayg).zfill(2)
                        year = f"20{str_arg(yr).zfill(2)}"
                        match_source = "Filename EPBDO parse"

                    token_match = re_arg.search(r"(sv|dv|db)(\d{1,})", fn_lower)

                    if not token_match:
                        token_match = re_arg.search(r"(sv|dv|db)", fn_lower)

                    if token_match:
                        token = token_match.group(1)

                        token_map = {
                            "sv": "straight",
                            "dv": "deferred",
                            "db": "debit",
                        }

                        extra_path = token_map.get(token, extra_path)

                        if len_arg(token_match.groups()) >= 2 and token_match.group(2):
                            digits_after = re_arg.sub(r"\D", "", token_match.group(2))

                            if len_arg(digits_after) >= 4:
                                branch = str_arg(digits_after[:4]).zfill(4)
                            else:
                                branch = str_arg(digits_after).zfill(4)

                        match_source = f"Filename token {token.upper()} branch override"

            # ---------------------------------------------------------
            # Track unmatched / fallback files
            # ---------------------------------------------------------
            if bank == "unknown_bank":
                unmatched_item = {
                    "file_path": file_path,
                    "file_name": file_name,
                    "reason": "No bank matched after enabled rules",
                    "company": str_arg(company).zfill(3) if str_arg(company).isdigit() else str_arg(company),
                    "branch": str_arg(branch).zfill(4) if str_arg(branch).isdigit() else str_arg(branch),
                    "year": str_arg(year),
                    "month": str_arg(month).zfill(2),
                    "day": str_arg(day).zfill(2),
                    "match_source": str_arg(match_source),
                    "matched_reference_id": str_arg(matched_reference_id),
                    "pbdo_locked": pbdo_locked,
                    "ttl_locked": ttl_locked,
                    "raw_numeric_blocks": signal.get("raw_numeric_blocks", [])[:5],
                    "content_digit_count": len_arg(signal.get("content_digit_candidates", [])),
                    "branch_text_count": len_arg(signal.get("branch_text_candidates", [])),
                    "zip_filename_digit_count": len_arg(signal.get("zip_inner_filename_candidates", [])),
                    "zip_content_digit_count": len_arg(signal.get("zip_inner_content_digit_candidates", [])),
                }

            routed_item = {
                **signal,
                "route_family": route_family,
                "bank": str_arg(bank),
                "company": str_arg(company).zfill(3) if str_arg(company).isdigit() else str_arg(company),
                "branch": str_arg(branch).zfill(4) if str_arg(branch).isdigit() else str_arg(branch),
                "extra_path": str_arg(extra_path),
                "year": str_arg(year),
                "month": str_arg(month).zfill(2),
                "day": str_arg(day).zfill(2),
                "match_source": str_arg(match_source),
                "matched_reference_id": str_arg(matched_reference_id),
                "pbdo_locked": pbdo_locked,
                "ttl_locked": ttl_locked,
            }
            return routed_item, unmatched_item, None

        except Exception as exc:
            return None, None, {
                "file_path": signal.get("file_path"),
                "file_name": signal.get("file_name"),
                "error": str_arg(exc),
            }





routed_files = []
error_files = []
unmatched_files = []
for signal in signals:
    routed_item, unmatched_item, error = route_signal(signal)
    if routed_item:
        routed_files.append(routed_item)
    if unmatched_item:
        unmatched_files.append(unmatched_item)
    if error:
        error_files.append(error)



def group_examples_by_extension(items):
    groups = {}
    for item in items:
        extension = str(item.get("extension") or Path(item.get("file_name", "")).suffix or "no extension").lower()
        reason = str(item.get("reason") or item.get("match_source") or "routed")
        key = f"{extension}|{reason}"
        if key not in groups:
            groups[key] = {
                "extension": extension,
                "count": 0,
                "example": item.get("file_name"),
                "reason": reason,
                "bank": item.get("bank"),
                "matched_reference_id": item.get("matched_reference_id"),
            }
        groups[key]["count"] += 1
    return list(groups.values())

# =========================================================
# Save outputs
# =========================================================

bank_counts = {}
bank_examples = {}

for item in routed_files:
    bank_name = item.get("bank", "unknown_bank")
    bank_counts[bank_name] = bank_counts.get(bank_name, 0) + 1
    if bank_name not in bank_examples:
        bank_examples[bank_name] = {
            "file_name": item.get("file_name"),
            "extension": item.get("extension"),
            "matched_reference_id": item.get("matched_reference_id"),
            "company": item.get("company"),
            "branch": item.get("branch"),
            "match_source": item.get("match_source"),
        }

routed_file = run_dir / "routed_files.json"
routing_errors_file = run_dir / "routing_errors.json"
unmatched_file = run_dir / "unmatched_files.json"

routed_file.write_text(json.dumps(routed_files, ensure_ascii=False), encoding="utf-8")
routing_errors_file.write_text(json.dumps(error_files, ensure_ascii=False), encoding="utf-8")
unmatched_file.write_text(json.dumps(unmatched_files, ensure_ascii=False), encoding="utf-8")

log(
    f"Routing complete: routed={len(routed_files)}, errors={len(error_files)}, unmatched={len(unmatched_files)}",
    level="info",
)

result = {
    "status": "routed",
    "routed_file": str(routed_file),
    "routing_errors_file": str(routing_errors_file),
    "unmatched_file": str(unmatched_file),
    "total_routed": len(routed_files),
    "total_errors": len(error_files),
    "total_unmatched": len(unmatched_files),
    "bank_counts": bank_counts,
    "bank_examples": bank_examples,
    "sample_routed": group_examples_by_extension(routed_files),
    "sample_errors": group_examples_by_extension(error_files),
    "sample_unmatched": group_examples_by_extension(unmatched_files),
    "routed_extension_summary": group_examples_by_extension(routed_files),
    "unmatched_extension_summary": group_examples_by_extension(unmatched_files),
}
